#include <iostream>
#include <memory>
#include <string>
#include <vector>

class UniqueResource
{
    std::string m_name;

public:
    UniqueResource(std::string name)
        : m_name{ std::move(name) }
    {
    }

    const std::string& getName() const { return m_name; }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<std::unique_ptr<UniqueResource>> source;
    for (int i{ 0 }; i < n; ++i)
    {
        std::string name{};
        std::cin >> name;
        source.push_back(std::make_unique<UniqueResource>(std::move(name)));
    }

    std::vector<std::unique_ptr<UniqueResource>> dest;

    for (auto& ptr : source)
    {
        std::cout << "moved: " << ptr->getName() << '\n';
        dest.push_back(std::move(ptr));
    }

    std::cout << "dest:";
    for (const auto& ptr : dest)
        std::cout << ' ' << ptr->getName();
    std::cout << '\n';

    bool allNull{ true };
    for (const auto& ptr : source)
    {
        if (ptr != nullptr)
        {
            allNull = false;
            break;
        }
    }
    std::cout << "source empty: " << (allNull ? "true" : "false") << '\n';

    return 0;
}

