#include <iostream>
#include <memory>
#include <string>

int main()
{
    std::string name{};
    std::cin >> name;

    auto original{ std::make_shared<std::string>(std::move(name)) };
    std::cout << "created " << *original << ", refs: " << original.use_count() << '\n';

    auto copy{ original };
    std::cout << "copied, refs: " << original.use_count() << '\n';

    std::weak_ptr<std::string> weak{ original };
    std::cout << "weak created, refs: " << original.use_count() << '\n';

    std::cout << "weak expired: " << (weak.expired() ? "true" : "false") << '\n';

    {
        auto locked{ weak.lock() };
        std::cout << "locked, refs: " << original.use_count() << '\n';
    }
    std::cout << "lock released, refs: " << original.use_count() << '\n';

    copy.reset();
    std::cout << "copy reset, refs: " << original.use_count() << '\n';

    original.reset();
    std::cout << "original reset, refs: " << original.use_count() << '\n';

    std::cout << "weak expired: " << (weak.expired() ? "true" : "false") << '\n';

    return 0;
}
